66→#ifdef USE_OX_BRIDGE
67→// Ensure FVI data callbacks are registered before any OCaml FVI call.
68→// These are needed by player_is_visible_from_object_v2 and compute_vis_and_vec_v2
69→// which call OCaml FVI functions that perform Fetch_segment_data effects.
70→static void ensure_fvi_data_callbacks_registered()
71→{
72→	static int registered = 0;
73→	if (registered) return;
74→	registered = 1;
75→	cd_ox_register_fvi_data_callbacks(
76→		// fetch_segment_data: pack one segment's 87 ints
77→		[](int segnum, int32_t* out) {
78→			segment* seg = &Segments[segnum];
79→			for (int i = 0; i < 6; i++)
80→				out[i] = seg->children[i];
81→			for (int i = 0; i < 6; i++)
82→				out[6 + i] = seg->sides[i].type;
83→			for (int i = 0; i < 8; i++)
84→				out[12 + i] = seg->verts[i];
85→			for (int sn = 0; sn < 6; sn++)
