        Val_int(obj_pos_x), Val_int(obj_pos_y), Val_int(obj_pos_z),
        Val_int(num_awareness_events), Val_int(is_d2)
    });

    /* result is an OCaml array of 7 ints:
       [0] = return value, [1] = should_store,
       [2..6] = segnum, pos_x, pos_y, pos_z, event_type */
