    for (int i = 0; i < gp_len; i++)
        Store_field(v_gp, i, Val_long(gun_points_flat[i]));

    v_gd = caml_alloc(gp_len, 0);
    for (int i = 0; i < gp_len; i++)
        Store_field(v_gd, i, Val_long(gun_dirs_flat[i]));

    value args[18] = {
